diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..d115cbd32cb9 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1849,6 +1849,69 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  ? static_cast<Value *>(LHS)
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }
+  // Simplify AND/OR of two floating point comparisons with the same operand
+  // and different constant operands.
+  // For OR: (X < C1) | (X < C2) -> X < max(C1, C2)
+  //         (X > C1) | (X > C2) -> X > min(C1, C2)
+  // For AND: (X < C1) & (X < C2) -> X < min(C1, C2)
+  //          (X > C1) & (X > C2) -> X > max(C1, C2)
+  if (LHS0 == RHS0) {
+    const APFloat *LHSConst, *RHSConst;
+    if (match(LHS1, m_APFloat(LHSConst)) && match(RHS1, m_APFloat(RHSConst))) {
+      // Check if predicates are relational (not equality and not ORD/UNO)
+      if (PredL != PredR) {
+        // Check for swapped operands: (C1 < X) vs (C2 < X) 
+        // which is equivalent to (X > C1) vs (X > C2)
+        if (LHS0 == RHS1 && LHS1 == RHS0) {
+          // Both have swapped operands, compare as if LHS0/RHS0 are on right
+        } else {
+          // Different predicates, can't simplify
+        }
+      }
+      
+      // Only handle same predicate case for now
+      if (PredL == PredR) {
+        bool IsLessThan = (PredL == FCmpInst::FCMP_OLT || 
+                          PredL == FCmpInst::FCMP_OLE ||
+                          PredL == FCmpInst::FCMP_ULT || 
+                          PredL == FCmpInst::FCMP_ULE);
+        bool IsGreaterThan = (PredL == FCmpInst::FCMP_OGT || 
+                             PredL == FCmpInst::FCMP_OGE ||
+                             PredL == FCmpInst::FCMP_UGT || 
+                             PredL == FCmpInst::FCMP_UGE);
+        
+        if (IsLessThan || IsGreaterThan) {
+          int Cmp = LHSConst->compare(*RHSConst);
+          // For less-than predicates:
+          //   OR: want larger constant (covers more values)
+          //   AND: want smaller constant (more restrictive)
+          // For greater-than predicates:
+          //   OR: want smaller constant (covers more values)
+          //   AND: want larger constant (more restrictive)
+          bool ChooseLHS;
+          if (IsLessThan) {
+            if (IsAnd) {
+              // AND with less-than: choose smaller constant
+              ChooseLHS = (Cmp == APFloat::cmpLessThan);
+            } else {
+              // OR with less-than: choose larger constant
+              ChooseLHS = (Cmp == APFloat::cmpGreaterThan);
+            }
+          } else {
+            // IsGreaterThan
+            if (IsAnd) {
+              // AND with greater-than: choose larger constant
+              ChooseLHS = (Cmp == APFloat::cmpGreaterThan);
+            } else {
+              // OR with greater-than: choose smaller constant
+              ChooseLHS = (Cmp == APFloat::cmpLessThan);
+            }
+          }
+          return ChooseLHS ? LHS : RHS;
+        }
+      }
+    }
+  }

   return nullptr;
 }

